import useAxios from 'axios-hooks';
import '../App.css';
// import { Component } from 'react';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
// import BootstrapTable from 'react-bootstrap-table-next';

// const columns =[{
//     dataField: 'id',
//     text: 'ID'
// },{
//     dataField: 'name_sing',
//     text: 'Название знака'
// }];

// const const_data = []

function Sing() {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial' }}>
        <h1>Данные из Flask API</h1>

        <div style={{ marginBottom: '20px' }}>
            <button 
            onClick={() => refetch()} 
            style={{ padding: '10px 20px', marginRight: '10px' }}
            >
            Обновить данные
            </button>

        </div>

        {data && (
            <div>
            <h3>Статус: {data.message}</h3>

            <table style={{ 
                borderCollapse: 'collapse', 
                width: '100%',
                marginTop: '20px'
            }}>
                <thead>
                <tr style={{ background: '#f5f5f5' }}>
                    <th style={{ padding: '10px', border: '1px solid #ddd' }}>ID</th>
                    <th style={{ padding: '10px', border: '1px solid #ddd' }}>Название дорожного знака</th>
                </tr>
                </thead>
                <tbody>
                {data.users.map(user => (
                    <tr key={user.id}>
                    <td style={{ padding: '10px', border: '1px solid #ddd' }}>
                        {user.id}
                    </td>
                    <td style={{ padding: '10px', border: '1px solid #ddd' }}>
                        {user.name_sing}
                    </td>
                    </tr>
                ))}
                </tbody>
            </table>
            </div>
        )}
        </div>
    );
}

